# %% ../nbs/10_seo_content_analysis.ipynb #9b955c78
def calculate_keyword_density(content: str, keyword: str) -> dict:
    """Calculate keyword density using word-level matching"""
    content_lower = content.lower()
    keyword_lower = keyword.lower()

    content_words = content_lower.split()
    keyword_words = keyword_lower.split()
    n = len(keyword_words)

    positions = []
    for i in range(len(content_words) - n + 1):
        if content_words[i:i + n] == keyword_words:
            positions.append(i)

    total_words = len(content_words)
    count = len(positions)
    density = (count / total_words * 100) if total_words > 0 else 0

    return {
        "keyword": keyword,
        "count": count,
        "density": density,
        "positions": positions,
    }


